rules.pseudocode:
taste_vals = {food_id: food.palatability for food in visible_foods}
health_vals = {food_id: (1.0 - food.palatability) for food in visible_foods}
tastiest_id = argmax(taste_vals)
healthiest_id = argmax(health_vals)
if tastiest_id != healthiest_id:
    K = taste_vals[tastiest_id] - taste_vals[healthiest_id]
else:
    K = 0.0

for each action a:
    P_a = exp(beta * CCV_a) / sum(exp(beta * CCV_j) for j in candidate_actions)
selected_action = sample from distribution P
